{
  "experiment_plan": {
    "what_to_compare": "淮河境界の直近にある都市を、境界の北側（無料石炭暖房政策あり）と南側（政策なし）で比較する。主要比較は、境界からの緯度距離が連続的に変化する都市群における、冬季TSP曝露、平均寿命、心肺疾患死亡率、寒冷関連死亡、呼吸器疾患死亡、および補助的な社会経済・医療アクセス指標の境界不連続である。",
    "what_to_measure": "1) 冬季TSP濃度の境界不連続、2) 平均寿命または年齢調整死亡率の境界不連続、3) 心肺疾患死亡率、寒冷関連死亡、呼吸器疾患死亡、4) SO2、煤煙、室内汚染の代理指標、5) 医療供給、所得、都市化、住宅断熱、暖房利用率などの交絡候補、6) 境界近傍での事前トレンドと地理的連続性。",
    "procedure": "地理的RDDを実施する。まず境界からの距離をrunning variableとして、複数のバンド幅と多項式次数で局所推定を行う。次に、TSPの第一段階不連続を確認し、その後に寿命・死亡率アウトカムの不連続を推定する。補助分析として、(a) 心肺疾患・呼吸器・寒冷関連死亡への影響、(b) SO2や煤煙など他の燃焼由来曝露の追加説明力、(c) 医療アクセス・所得・都市化の境界不連続の有無、(d) 住宅断熱や暖房利用率による効果修飾、(e) 季節別・年齢別の異質性を検証する。推定は、バンド幅感度分析、3次多項式に加え低次多項式・局所線形推定を比較し、境界近傍の共変量バランスとプレトレンドを確認する。結果は、各仮説ごとに事前に定めた判定規則に従って解釈する。",
    "identification_assumptions": [
      {
        "id": "IA1",
        "description": "淮河境界の近傍では、政策以外の要因が境界をまたいで連続的に変化し、潜在アウトカムは境界で滑らかである。",
        "if_violated": "境界近傍で医療、所得、都市化、気候、人口構成などに不連続が存在し、寿命差を政策効果として識別できない。"
      },
      {
        "id": "IA2",
        "description": "境界からの距離に対して、都市が政策適用側を操作的に選択したり、境界近傍の都市配置が不連続に歪められていない。",
        "if_violated": "境界近傍の都市選定や行政区分が操作されている場合、RDDの局所比較が無効になる。"
      },
      {
        "id": "IA3",
        "description": "淮河境界は冬季TSP曝露に対して十分な第一段階を持ち、政策が汚染を実際に増加させる。",
        "if_violated": "境界をまたぐTSP不連続が弱い、または存在しない場合、健康アウトカムへの媒介経路を検証できない。"
      },
      {
        "id": "IA4",
        "description": "境界近傍での他の政策、医療制度変更、産業構造変化が、暖房政策と同時に不連続に発生していない。",
        "if_violated": "別政策や構造変化が同時に起きていると、観測された寿命差の原因を分離できない。"
      },
      {
        "id": "IA5",
        "description": "アウトカム測定誤差が境界の両側で系統的に異ならず、死亡統計や寿命推定が比較可能である。",
        "if_violated": "死亡登録や寿命推定の精度が地域で異なると、見かけの不連続が生じる。"
      }
    ],
    "hypothesis_rules": [
      {
        "id": "H1",
        "accept_if": "境界でTSPに有意な上昇があり、同じ境界近傍で平均寿命が有意に低下し、かつ心肺疾患死亡率が同方向に上昇する。さらに、バンド幅・多項式次数を変えても符号と有意性が概ね維持される。",
        "reject_if": "TSPの不連続は確認されるが、平均寿命の不連続がゼロ近傍で安定し、心肺疾患死亡率も同方向に変化しない。",
        "hold_if": "TSPの第一段階は確認されるが、寿命・死亡率の推定がバンド幅や多項式次数に強く依存し、符号や有意性が不安定である。"
      },
      {
        "id": "H2",
        "accept_if": "TSP上昇が同程度でも、住宅断熱や暖房利用率が高い都市では平均寿命低下が小さく、寒冷関連死亡や冬季死亡の季節性が弱まるという効果修飾が確認される。",
        "reject_if": "住宅断熱や暖房利用率による効果修飾が見られず、TSP上昇に対する寿命低下が一様で、寒冷関連死亡の増加も観測されない。",
        "hold_if": "TSPと寿命の関係はあるが、住宅断熱・暖房利用率との交互作用が統計的に不明確で、寒冷関連死亡の季節性も一貫しない。"
      },
      {
        "id": "H3",
        "accept_if": "TSPを統制した後でも、SO2、煤煙、室内汚染の代理変数が平均寿命や心肺疾患死亡率を追加的に説明し、石炭依存度の高い地域ほど効果が大きい。",
        "reject_if": "TSPを統制すると、SO2、煤煙、室内汚染の代理変数は追加説明力を持たず、石炭依存度による異質性も見られない。",
        "hold_if": "TSP以外の燃焼由来指標は一部関連するが、追加説明力が弱いか、石炭依存度との関係が不安定である。"
      },
      {
        "id": "H4",
        "accept_if": "境界近傍で医療供給、所得、都市化などの共変量に不連続がなく、かつ寿命の不連続がTSPの不連続と整合的に残る。",
        "reject_if": "医療供給、所得、都市化などに境界不連続があり、寿命差がそれらの不連続と同方向・同程度で、TSP調整後に消失する。",
        "hold_if": "共変量の不連続は小さいが完全には排除できず、寿命差の因果解釈がなお曖昧である。"
      }
    ],
    "analysis_forks": [
      "バンド幅を狭くした局所推定と広くした推定を別々に実施する。",
      "3次多項式、低次多項式、局所線形推定を比較する。",
      "アウトカムを平均寿命、心肺疾患死亡率、寒冷関連死亡、呼吸器疾患死亡に分けて推定する。",
      "TSPのみを媒介として扱う分析と、SO2・煤煙・室内汚染を追加した多媒介分析を分ける。",
      "住宅断熱・暖房利用率による効果修飾を検証する分析を行う。",
      "医療アクセス、所得、都市化の共変量バランス検定を別途行う。",
      "季節別、年齢別、都市規模別の異質性分析を行う。",
      "プレトレンド検証と境界操作検定を別途実施する。"
    ]
  }
}
